// // This module decrements the 2-bit counter on each clock cycle and synchronously resets.
module counter_2bit(
    input clk,
    input reset,
    output reg [1:0] count);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 2'b00;
        end else begin
            count <= count + 1;
        end
    end
endmodule
